/*
 * sinh() test harness -- prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sinh  (test_sinh_opt.elf)
 *   2. Linked with toolchain's default sinh        (test_sinh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += sinh(vx);
#else
    double r = sinh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test suite                                */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                  /* smallest positive normal: 2^-1022 */
    emit(-DBL_MIN);
    emit(DBL_MAX);                  /* largest finite double: ~1.8e308, sinh overflows */
    emit(-DBL_MAX);

    /* --- Section 4: Tiny values where sinh(x) ~ x fast path (8) --- */
    emit(1.0e-300);
    emit(-1.0e-300);
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(1.0e-20);
    emit(-1.0e-20);

    /* --- Section 5: Near 1.0 ULP density (6) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 6: Key mathematical constants (14) --- */
    emit_u(0x3fe62e42fefa39efULL);  /* ln2 ~ 0.6931: sinh(ln2) = 0.75 exactly */
    emit_u(0xbfe62e42fefa39efULL);  /* -ln2 */
    emit(0.5);
    emit(-0.5);
    emit(0.1);
    emit(-0.1);
    emit(2.0);
    emit(-2.0);
    emit(5.0);
    emit(-5.0);
    emit(10.0);
    emit(-10.0);
    emit_u(0x4005bf0a8b145769ULL);  /* ln(10) ~ 2.3026 */
    emit_u(0xc005bf0a8b145769ULL);  /* -ln(10) */

    /* --- Section 7: Overflow threshold stress (8) --- */
    /* sinh overflows for x > ~710.47; double exp overflow is ~709.78 */
    emit_u(0x40862e42fefa39efULL);  /* exp overflow threshold: ~709.782 */
    emit_u(0x40862e42fefa39f0ULL);  /* one ULP above exp overflow threshold */
    emit_u(0x40862e42fefa39eeULL);  /* one ULP below exp overflow threshold */
    emit_u(0xc0862e42fefa39efULL);  /* negative exp overflow threshold */
    emit_u(0xc0862e42fefa39f0ULL);  /* one ULP above (toward -Inf) */
    emit_u(0xc0862e42fefa39eeULL);  /* one ULP below (toward zero) */
    emit(710.0);
    emit(-710.0);

    /* --- Section 8: Small-argument fast-path threshold boundaries (8) --- */
    emit_u(0x3fb0000000000000ULL);  /* 2^-12 ~ 2.44e-4 */
    emit_u(0xbfb0000000000000ULL);  /* -2^-12 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26 ~ 1.49e-8 */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
    emit_u(0x3f80000000000000ULL);  /* 2^-7 ~ 7.81e-3 */
    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
    emit_u(0x3f20000000000000ULL);  /* 2^-13 ~ 1.22e-4 */
    emit_u(0xbf20000000000000ULL);  /* -2^-13 */

    /* --- Section 9: Large arguments (10) --- */
    emit(20.0);
    emit(-20.0);
    emit(50.0);
    emit(-50.0);
    emit(88.0);
    emit(-88.0);
    emit(100.0);
    emit(-100.0);
    emit(500.0);
    emit(-500.0);

    /* --- Section 10: ULP neighbors of key values and mid-range hard cases (29) --- */
    /* ULP triplet around ln2 */
    emit_u(0x3fe62e42fefa39eeULL);  /* one ULP below ln2 */
    emit_u(0x3fe62e42fefa39f0ULL);  /* one ULP above ln2 */
    emit_u(0xbfe62e42fefa39eeULL);  /* one ULP below -ln2 (toward zero) */

    /* ULP triplet around 1.0 (double precision boundary) */
    emit_u(0x3ff0000000000002ULL);  /* two ULPs above 1.0 */
    emit_u(0xbff0000000000000ULL);  /* -1.0 exact */
    emit_u(0xbff0000000000002ULL);  /* two ULPs below -1.0 */

    /* Powers of 2 -- exponent boundary behavior */
    emit(4.0);
    emit(-4.0);
    emit(8.0);
    emit(-8.0);
    emit(16.0);
    emit(-16.0);
    emit(32.0);
    emit(-32.0);
    emit(64.0);
    emit(-64.0);

    /* Half-integer values -- midpoints between powers of 2 */
    emit(1.5);
    emit(-1.5);
    emit(2.5);
    emit(-2.5);
    emit(4.5);
    emit(-4.5);

    /* ULP triplet around sinh overflow boundary ~710.47 */
    emit_u(0x40862e42fefa39f8ULL);  /* several ULPs above exp threshold, sinh ~Inf */
    emit(709.0);
    emit(-709.0);

    /* Near-zero: 1e-10 exercises the x ~ tanh region boundary */
    emit(1.0e-10);
    emit(-1.0e-10);

    /* Midrange values */
    emit(3.0);
    emit(-3.0);
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 100] in 100 steps and [-100, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 100.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 100] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-100, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -5.0;
    double hi =  5.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf g_acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

